  1→@use '../../../libs/ui/components/src/lib/resizable/resizable.scss';
  2→
  3→// ─── Tailwind CSS ─────────────────────────────────────────────────────────────
  4→// Preflight is disabled in tailwind.config.js to avoid conflicts with
  5→// Angular Material. Only components + utilities are loaded.
  6→@tailwind base;
  7→@tailwind components;
  8→@tailwind utilities;
  9→
 10→// ─── Third-party ─────────────────────────────────────────────────────────────
 11→@import '@yangkghjh/videojs-aspect-ratio-panel/dist/videojs-aspect-ratio-panel.css';
 12→
 13→// ─── Google Fonts ─────────────────────────────────────────────────────────────
 14→@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap');
 15→
 16→// ─── Shared Components ────────────────────────────────────────────────────────
 17→
 18→app-root.macos-platform .current-playlist {
 19→    padding-top: 30px;
 20→}
 21→
 22→app-root.macos-platform app-navigation .portal-status-container {
 23→    padding-top: 30px;
 24→}
 25→
 26→// ─── Base ─────────────────────────────────────────────────────────────────────
 27→body,
 28→html {
 29→    user-select: none;
 30→    margin: 0;
 31→    padding: 0;
 32→    height: 100%;
 33→    font-family:
 34→        'Inter',
 35→        'Roboto',
 36→        'Helvetica Neue',
 37→        sans-serif;
 38→    -webkit-font-smoothing: antialiased;
 39→    -moz-osx-font-smoothing: grayscale;
 40→}
 41→
 42→// Re-enable context menu and text selection for input fields
 43→input,
 44→textarea {
 45→    user-select: text;
 46→}
 47→
 48→@media (display-mode: standalone) {
 49→    body {
 50→        overscroll-behavior-y: contain;
 51→        overflow: hidden;
 52→    }
 53→}
 54→
 55→// ─── Utilities ────────────────────────────────────────────────────────────────
 56→.mat-tab-label-active {
 57→    opacity: 1 !important;
 58→}
 59→
 60→input,
 61→button,
 62→textarea,
 63→:focus {
 64→    outline: none;
 65→}
 66→
 67→// ─── Dark Theme ───────────────────────────────────────────────────────────────
 68→.dark-theme {
 69→    background: var(--mat-sys-surface) !important;
 70→
 71→    // Refined scrollbar for dark mode
 72→    ::-webkit-scrollbar {
 73→        width: 6px;
 74→        height: 6px;
 75→    }
 76→
 77→    ::-webkit-scrollbar-track {
 78→        background: transparent;
 79→    }
 80→
 81→    ::-webkit-scrollbar-thumb {
 82→        background-color: var(--mat-sys-outline-variant);
 83→        border-radius: 999px;
 84→
 85→        &:hover {
 86→            background-color: var(--mat-sys-outline);
 87→        }
 88→    }
 89→}
 90→
 91→.scroll-viewport-portals {
 92→    min-height: calc(100vh - 170px) !important;
 93→    overflow-x: hidden !important;
 94→}
 95→
 96→.mat-drawer-inner-container {
 97→    overflow: hidden !important;
 98→}
 99→
100→.cdk-overlay-backdrop {
101→    backdrop-filter: blur(4px);
102→}
103→
104→// Full-screen overlay dialogs (global search/recent) must stay interactive in Electron.
105→.global-search-overlay,
106→.global-search-overlay .mat-mdc-dialog-surface,
107→.global-search-overlay .mat-mdc-dialog-container {
108→    app-region: no-drag;
109→}
110→

  1→@use 'sass:map';
  2→@use '@angular/material' as mat;
  3→@use 'styles';
  4→
  5→@include mat.elevation-classes();
  6→@include mat.app-background();
  7→
  8→// ─── Typography ─────────────────────────────────────────────────────────────
  9→$my-typography: mat.m2-define-typography-config(
 10→    $font-family: "'DM Sans', 'Inter', sans-serif",
 11→);
 12→@include mat.typography-hierarchy($my-typography);
 13→
 14→// ─── M3 Themes ───────────────────────────────────────────────────────────────
 15→$light-theme: mat.define-theme(
 16→    (
 17→        color: (
 18→            theme-type: light,
 19→            primary: mat.$violet-palette,
 20→            tertiary: mat.$cyan-palette,
 21→        ),
 22→        typography: (
 23→            plain-family: "'DM Sans', 'Inter', sans-serif",
 24→            brand-family: "'DM Sans', 'Inter', sans-serif",
 25→        ),
 26→    )
 27→);
 28→
 29→$dark-theme: mat.define-theme(
 30→    (
 31→        color: (
 32→            theme-type: dark,
 33→            primary: mat.$violet-palette,
 34→            tertiary: mat.$cyan-palette,
 35→        ),
 36→        typography: (
 37→            plain-family: "'DM Sans', 'Inter', sans-serif",
 38→            brand-family: "'DM Sans', 'Inter', sans-serif",
 39→        ),
 40→    )
 41→);
 42→
 43→// ─── Apply Themes ────────────────────────────────────────────────────────────
 44→html {
 45→    @include mat.all-component-themes($light-theme);
 46→
 47→    // ── Light theme design tokens ─────────────────────────────────────────
 48→    --app-shell-bg: #eef0f3;
 49→    --app-rail-bg: #eef0f3;
 50→    --app-header-bg: #eef0f3;
 51→    --app-content-bg: #f5f6f8;
 52→    --app-rail-border: transparent;
 53→    --app-search-bg: rgba(255, 255, 255, 0.7);
 54→    --app-search-border: rgba(0, 0, 0, 0.1);
 55→    --app-selection-color: #2f7bff;
 56→    --app-selection-on-color: #eef4ff;
 57→    --app-selection-surface: color-mix(
 58→        in srgb,
 59→        var(--app-selection-color) 14%,
 60→        transparent
 61→    );
 62→    --app-selection-surface-strong: color-mix(
 63→        in srgb,
 64→        var(--app-selection-color) 22%,
 65→        transparent
 66→    );
 67→    --app-selection-border: color-mix(
 68→        in srgb,
 69→        var(--app-selection-color) 52%,
 70→        transparent
 71→    );
 72→    --app-selection-glow: color-mix(
 73→        in srgb,
 74→        var(--app-selection-color) 34%,
 75→        transparent
 76→    );
 77→
 78→    // Content area
 79→    --app-content-shadow: -2px 4px 12px rgba(0, 0, 0, 0.06);
 80→
 81→    // Widget surfaces — no borders, layered backgrounds
 82→    --app-widget-bg: #ffffff;
 83→    --app-widget-header-bg: #fafbfc;
 84→    --app-widget-border: transparent;
 85→    --app-widget-shadow: 0 1px 3px rgba(0, 0, 0, 0.06), 0 4px 12px rgba(0, 0, 0, 0.04);
 86→    --app-widget-header-border: rgba(0, 0, 0, 0.06);
 87→    --app-card-hover-bg: #f0f2f5;
 88→    --app-separator: rgba(0, 0, 0, 0.14);
 89→
 90→    // Typography — subdued, not pure black
 91→    --app-heading-color: #1a1d23;
 92→    --app-body-color: #4a5060;
 93→    --app-muted-color: #8891a4;
 94→    --app-eyebrow-color: #7c8495;
 95→
 96→    // Provider accent colors
 97→    --app-provider-xtream: #6366f1;
 98→    --app-provider-stalker: #10b981;
 99→    --app-provider-m3u: #d97706;
100→
101→    // Hero
102→    --app-accent-gradient: linear-gradient(
103→        135deg,
104→        rgba(99, 102, 241, 0.08) 0%,
105→        rgba(168, 85, 247, 0.05) 100%
106→    );
107→    --app-hero-surface: rgba(99, 102, 241, 0.04);
108→
109→    .dark-theme {
110→        @include mat.all-component-colors($dark-theme);
111→
112→        // ── Dark graphite theme ────────────────────────────────────────────
113→        // Inspired by both Slack (sidebar distinction) and GitButler (data density)
114→        // Key principle: clearly distinct surface layers using graphite steps
115→        // Darkest → lightest: #0d0f12 → #141720 → #1c2030 → #222840
116→
117→        // App shell & navigation
118→        --app-shell-bg: #0d0f12;
119→        --app-rail-bg: #111318;
120→        --app-header-bg: #111318;
121→        --app-content-bg: #161a22;
122→        --app-rail-border: transparent;
123→        --app-search-bg: rgba(255, 255, 255, 0.05);
124→        --app-search-border: rgba(255, 255, 255, 0.09);
125→        --app-selection-color: #78adff;
126→        --app-selection-on-color: #071225;
127→        --app-selection-surface: color-mix(
128→            in srgb,
129→            var(--app-selection-color) 18%,
130→            transparent
131→        );
132→        --app-selection-surface-strong: color-mix(
133→            in srgb,
134→            var(--app-selection-color) 28%,
135→            transparent
136→        );
137→        --app-selection-border: color-mix(
138→            in srgb,
139→            var(--app-selection-color) 62%,
140→            transparent
141→        );
142→        --app-selection-glow: color-mix(
143→            in srgb,
144→            var(--app-selection-color) 44%,
145→            transparent
146→        );
147→
148→        // Content area
149→        --app-content-shadow: -4px 8px 20px rgba(0, 0, 0, 0.18);
150→
151→        // Widget surfaces — NO border, surface contrast does the work
152→        // Widgets sit on content-bg (#161a22), so widget-bg is notably lighter
153→        --app-widget-bg: #1e2330;
154→        --app-widget-header-bg: #232840;
155→        --app-widget-border: transparent;
156→        --app-widget-shadow: none;
157→        --app-widget-header-border: rgba(255, 255, 255, 0.05);
158→        --app-card-hover-bg: #252b3a;
159→        --app-separator: rgba(255, 255, 255, 0.14);
160→
161→        // Typography — NOT pure white. Warm graphite-tinted whites
162→        --app-heading-color: #d8dce8;       // soft off-white, not #fff
163→        --app-body-color: #8b93a8;          // muted blue-grey
164→        --app-muted-color: #5c6478;         // dimmed
165→        --app-eyebrow-color: #6b7494;       // eyebrow labels
166→
167→        // Provider accents (slightly brighter for dark bg)
168→        --app-provider-xtream: #818cf8;
169→        --app-provider-stalker: #34d399;
170→        --app-provider-m3u: #fbbf24;
171→
172→        // Hero section
173→        --app-accent-gradient: linear-gradient(
174→            135deg,
175→            rgba(99, 102, 241, 0.12) 0%,
176→            rgba(168, 85, 247, 0.07) 100%
177→        );
178→        --app-hero-surface: rgba(30, 35, 48, 0.9);
179→    }
180→}
