120→.play-btn {
121→    --play-btn-bg: var(--play-idle-bg);
122→    --play-btn-fg: var(--play-idle-fg);
123→    --play-btn-border: var(--play-idle-border);
124→    --play-btn-shadow: var(--play-idle-shadow);
125→
126→    position: relative;
127→    isolation: isolate;
128→    overflow: hidden;
129→    display: inline-flex;
130→    align-items: center;
131→    gap: 12px;
132→    padding: 12px 26px;
133→    min-height: 54px;
134→    font-size: 1rem;
135→    font-weight: 600;
136→    letter-spacing: 0.01em;
137→    background: var(--play-btn-bg);
138→    background-size: 140% 140%;
139→    background-position: 0% 50%;
140→    color: var(--play-btn-fg);
141→    border: 1px solid var(--play-btn-border);
142→    border-radius: 16px;
143→    box-shadow: var(--play-btn-shadow);
144→    cursor: pointer;
145→    transition:
146→        transform 220ms cubic-bezier(0.22, 1, 0.36, 1),
147→        background-position 280ms ease,
148→        box-shadow 260ms ease,
149→        border-color 220ms ease,
150→        color 220ms ease,
151→        filter 220ms ease;
152→
153→    &::before {
154→        content: '';
155→        position: absolute;
156→        inset: 1px;
157→        border-radius: inherit;
158→        background:
159→            linear-gradient(115deg, rgba(255, 255, 255, 0.34), transparent 36%),
160→            linear-gradient(180deg, rgba(255, 255, 255, 0.18), transparent 62%);
161→        opacity: 0.7;
162→        transition: opacity 220ms ease;
163→        z-index: -1;
164→    }
165→
166→    &:hover:not(:disabled) {
167→        transform: translateY(-2px);
168→        background-position: 100% 50%;
169→        box-shadow:
170→            var(--play-btn-shadow),
171→            0 10px 20px rgba(255, 255, 255, 0.16) inset;
172→    }
173→
174→    &:hover:not(:disabled)::before {
175→        opacity: 0.95;
176→    }
177→
178→    &:active:not(:disabled) {
179→        transform: translateY(0);
180→        box-shadow: var(--play-btn-shadow);
181→    }
182→
183→    &:disabled {
184→        cursor: progress;
185→        opacity: 1;
186→        filter: saturate(1.05);
187→    }
188→
189→    mat-icon {
190→        font-size: 24px;
191→        width: 24px;
192→        height: 24px;
193→        transition:
194→            transform 220ms cubic-bezier(0.22, 1, 0.36, 1),
195→            color 220ms ease,
196→            filter 220ms ease;
197→    }
198→
199→    &:hover:not(:disabled) .play-btn__icon {
200→        transform: scale(1.08);
201→    }
202→
203→    &__icon-shell {
204→        flex: 0 0 auto;
205→        display: inline-flex;
206→        align-items: center;
207→        justify-content: center;
208→        width: 34px;
209→        height: 34px;
210→        border-radius: 999px;
211→        background: var(--play-icon-shell-bg);
212→        border: 1px solid var(--play-icon-shell-border);
213→        box-shadow:
214→            inset 0 1px 0 rgba(255, 255, 255, 0.38),
215→            0 6px 14px rgba(0, 0, 0, 0.08);
216→        backdrop-filter: blur(10px);
217→        transition:
218→            transform 220ms ease,
219→            background-color 220ms ease,
220→            border-color 220ms ease,
221→            box-shadow 220ms ease;
222→    }
223→
224→    &__label {
225→        display: inline-flex;
226→        align-items: center;
227→        min-width: 0;
228→    }
229→
230→    &--state-launching,
231→    &--state-stop {
232→        color: var(--play-btn-fg);
233→    }
234→
235→    &--state-launching {
236→        --play-btn-bg: var(--play-launching-bg);
237→        --play-btn-fg: var(--play-launching-fg);
238→        --play-btn-border: var(--play-launching-border);
239→        --play-btn-shadow: var(--play-launching-shadow);
240→        animation: playButtonPulse 1.8s ease-in-out infinite;
241→
242→        .play-btn__icon-shell {
243→            box-shadow:
244→                inset 0 1px 0 rgba(255, 255, 255, 0.42),
245→                0 10px 22px rgba(184, 89, 26, 0.2);
246→        }
247→
248→        .play-btn__icon {
249→            animation: playIconLaunch 1.15s cubic-bezier(0.55, 0, 0.45, 1) infinite;
250→        }
251→    }
252→
253→    &--state-stop {
254→        --play-btn-bg: var(--play-stop-bg);
255→        --play-btn-fg: var(--play-stop-fg);
256→        --play-btn-border: var(--play-stop-border);
257→        --play-btn-shadow: var(--play-stop-shadow);
258→
259→        .play-btn__icon-shell {
260→            box-shadow:
261→                inset 0 1px 0 rgba(255, 255, 255, 0.4),
262→                0 12px 24px rgba(145, 38, 53, 0.18);
263→        }
264→
265→        .play-btn__icon {
266→            animation: playIconStop 1.2s ease-in-out infinite;
267→        }
268→    }
269→}
