  1→@let item = selectedItem();
  2→@if (item && item.info) {
  3→    <app-content-hero
  4→        [title]="item.info?.name || item?.movie_data?.name"
  5→        [description]="item.info.description || item.info.plot"
  6→        [posterUrl]="item.info.movie_image"
  7→        [backdropUrl]="item.info?.backdrop_path?.[0]"
  8→        (backClicked)="goBack()"
  9→    >
 10→        <ng-container hero-tags>
 11→            @if (item.info?.releasedate) {
 12→                <span class="details__tag">{{
 13→                    item.info.releasedate | slice: 0 : 4
 14→                }}</span>
 15→            }
 16→            @if (item.info?.genre) {
 17→                <span class="details__tag">{{ item.info.genre }}</span>
 18→            }
 19→            @if (item.info?.duration) {
 20→                <span class="details__tag">{{ item.info.duration }}</span>
 21→            }
 22→            @if (item.info?.rating_imdb) {
 23→                <span class="details__tag details__tag--rating">
 24→                    ⭐ {{ item.info.rating_imdb }}
 25→                </span>
 26→            }
 27→            @if (item.info?.country) {
 28→                <span class="details__tag">{{ item.info.country }}</span>
 29→            }
 30→        </ng-container>
 31→
 32→        <ng-container hero-meta>
 33→            @if (item.info?.actors || item.info?.cast) {
 34→                <div class="details__meta-item">
 35→                    <span class="label">{{ 'XTREAM.ACTORS' | translate }}</span>
 36→                    <span class="value">{{
 37→                        item.info.actors || item.info.cast
 38→                    }}</span>
 39→                </div>
 40→            }
 41→            @if (item.info?.director) {
 42→                <div class="details__meta-item">
 43→                    <span class="label">{{
 44→                        'XTREAM.DIRECTOR' | translate
 45→                    }}</span>
 46→                    <span class="value">{{ item.info.director }}</span>
 47→                </div>
 48→            }
 49→            @if (item.info?.rating_kinopoisk) {
 50→                <div class="details__meta-item">
 51→                    <span class="label">{{
 52→                        'XTREAM.KINOPOISK_RATING' | translate
 53→                    }}</span>
 54→                    <span class="value">{{ item.info.rating_kinopoisk }}</span>
 55→                </div>
 56→            }
 57→        </ng-container>
 58→
 59→        <ng-container hero-actions>
 60→            @if (hasPlaybackPosition()) {
 61→                <button
 62→                    class="play-btn play-btn--resume"
 63→                    (click)="onPrimaryAction(item)"
 64→                    [disabled]="isExternalLaunchPending()"
 65→                    [class.play-btn--state-launching]="externalPrimaryButtonState() === 'launching'"
 66→                    [class.play-btn--state-stop]="externalPrimaryButtonState() === 'stop'"
 67→                >
 68→                    <span class="play-btn__icon-shell" aria-hidden="true">
 69→                        <mat-icon class="play-btn__icon">{{
 70→                            externalPrimaryIcon()
 71→                        }}</mat-icon>
 72→                    </span>
 73→                    <span class="play-btn__label">
 74→                        @if (externalPrimaryLabel(); as label) {
 75→                            {{ label }}
 76→                        } @else {
 77→                            {{ 'XTREAM.RESUME' | translate }}
 78→                            {{ formatPosition() }}
 79→                        }
 80→                    </span>
 81→                </button>
 82→                @if (!isExternalStopAction()) {
 83→                    <button
 84→                        class="play-btn play-btn--restart"
 85→                        (click)="playVod(item)"
 86→                    >
 87→                        <mat-icon>replay</mat-icon>
 88→                        {{ 'XTREAM.RESTART' | translate }}
 89→                    </button>
 90→                }
 91→            } @else {
 92→                <button
 93→                    class="play-btn"
 94→                    (click)="onPrimaryAction(item)"
 95→                    [disabled]="isExternalLaunchPending()"
 96→                    [class.play-btn--state-launching]="externalPrimaryButtonState() === 'launching'"
 97→                    [class.play-btn--state-stop]="externalPrimaryButtonState() === 'stop'"
 98→                >
 99→                    <span class="play-btn__icon-shell" aria-hidden="true">
100→                        <mat-icon class="play-btn__icon">{{
101→                            externalPrimaryIcon()
102→                        }}</mat-icon>
103→                    </span>
104→                    <span class="play-btn__label">
105→                        @if (externalPrimaryLabel(); as label) {
106→                            {{ label }}
107→                        } @else {
108→                            {{ 'XTREAM.PLAY' | translate }}
109→                        }
110→                    </span>
111→                </button>
112→            }
113→            @if (!isFavorite()) {
114→                <button class="favorite-btn" (click)="toggleFavorite()">
115→                    <mat-icon>add</mat-icon>
116→                    {{ 'PORTALS.ADD_TO_FAVORITES' | translate }}
117→                </button>
118→            } @else {
119→                <button
120→                    class="favorite-btn favorite-btn--active"
121→                    (click)="toggleFavorite()"
122→                >
123→                    <mat-icon>check</mat-icon>
124→                    {{ 'PORTALS.REMOVE_FROM_FAVORITES' | translate }}
125→                </button>
126→            }
127→            @if (isElectron()) {
128→                @if (isDownloaded()) {
129→                    <button
130→                        class="download-btn download-btn--completed"
131→                        (click)="playFromLocal()"
132→                    >
133→                        <mat-icon>play_circle</mat-icon>
134→                        {{ 'DOWNLOADS.PLAY_LOCAL' | translate }}
135→                    </button>
136→                } @else if (isDownloading()) {
137→                    <button
138→                        class="download-btn download-btn--downloading"
139→                        disabled
140→                    >
141→                        <mat-icon>downloading</mat-icon>
142→                        {{ 'DOWNLOADS.STATUS.DOWNLOADING' | translate }}
143→                    </button>
144→                } @else {
145→                    <button class="download-btn" (click)="downloadVod(item)">
146→                        <mat-icon>download</mat-icon>
147→                        {{ 'DOWNLOADS.DOWNLOAD' | translate }}
148→                    </button>
149→                }
150→            }
151→        </ng-container>
152→
153→        @if (inlinePlayback(); as playback) {
154→            <app-portal-inline-player
155→                [playback]="playback"
156→                (timeUpdate)="handleInlineTimeUpdate($event)"
157→                (closed)="closeInlinePlayer()"
158→                (streamUrlCopied)="showCopyNotification()"
159→            />
160→        }
161→
162→        @if (item.info?.youtube_trailer) {
163→            <div class="youtube-trailer">
164→                <h3>{{ 'XTREAM.YOUTUBE_TRAILER' | translate }}</h3>
165→                <div class="trailer-wrapper">
166→                    <iframe
167→                        [src]="
168→                            'https://www.youtube.com/embed/' +
169→                                item.info.youtube_trailer | safe
170→                        "
171→                        title="YouTube video player"
172→                        allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share"
173→                        referrerpolicy="strict-origin-when-cross-origin"
174→                        allowfullscreen
175→                    ></iframe>
176→                </div>
177→            </div>
178→        }
179→    </app-content-hero>
180→} @else if (detailsError()) {
181→    <app-content-hero
182→        [errorMessage]="detailsError()"
183→        (backClicked)="goBack()"
184→    />
185→} @else {
186→    <app-content-hero [isLoading]="true" (backClicked)="goBack()" />
187→}
