file.content:
@use '@angular/material' as mat;

:host {
    display: flex;
    flex-direction: column;
    height: 100%;
    min-height: 0;
}

.scroll-viewport {
    height: 100%;
    overflow-x: hidden;
    width: 100%;

    ::ng-deep .cdk-virtual-scroll-content-wrapper {
        width: 100%;
        max-width: 100%;
    }
}

.search-panel {
    padding: 10px 0 0 0;
    display: flex;
    justify-content: center;
}

.search-bar {
    @include mat.form-field-density(-5);

    & {
        width: 96%;
    }
}

#all-channels {
    flex: 1;
    min-height: 0;
    overflow: hidden;
}

.channel-list {
    overflow-x: hidden;
}

::ng-deep {
    .search-bar {
        div {
            border-radius: 20px;
        }
    }

    div[matformfieldlineripple],
    .mat-mdc-form-field-subscript-wrapper {
        display: none;
    }
}

[type='search']::-webkit-search-cancel-button {
    -webkit-appearance: none;
    cursor: pointer;
    appearance: none;
    height: 10px;
    width: 10px;
    background-image: url('data:image/svg+xml;base64,REDACTED');
    background-size: 10px 10px;
    color: #fff;
}

.no-results {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 48px 24px;
    text-align: center;
    height: calc(100vh - 220px);
}

.no-results-icon {
    font-size: 48px;
    width: 48px;
    height: 48px;
    opacity: 0.5;
    margin-bottom: 16px;
}

.no-results-title {
    font-size: 1.1rem;
    font-weight: 500;
    margin-bottom: 8px;
}

.no-results-hint {
    opacity: 0.7;
    font-size: 0.9rem;
}

@media only screen and (max-width: 599px) {
    /* Mobile responsive tweaks if needed */
}

