@use '../../styles/skeleton';

:host {
    display: flex;
    flex-direction: column;
    height: 100%;
    overflow: hidden;
}

.skeleton-list {
    flex: 1;
    overflow: hidden;
}

.skeleton-grid {
    flex: 1;
    overflow: hidden;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(148px, 1fr));
    gap: 16px;
    padding: 16px;
    align-content: start;
}

.collection-header {
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 10px 16px;
    flex-shrink: 0;
    border-bottom: 1px solid var(--mat-sys-outline-variant);
}

.collection-title {
    font-size: 15px;
    font-weight: 600;
    color: var(--mat-sys-on-surface);
    margin-right: auto;
}

.content-toggle,
.scope-toggle {
    .toggle-label {
        margin-left: 4px;
        font-size: 12px;
    }

    mat-icon {
        font-size: 18px;
        width: 18px;
        height: 18px;
    }
}

app-unified-live-tab,
app-unified-grid-tab {
    flex: 1;
    min-height: 0;
    display: flex;
    flex-direction: column;
}

.empty-state {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 64px 24px;
    flex: 1;
    text-align: center;
    color: var(--mat-sys-on-surface-variant);

    .empty-icon {
        font-size: 56px;
        height: 56px;
        width: 56px;
        margin-bottom: 16px;
        opacity: 0.4;
    }

    .empty-title {
        font-size: 14px;
        font-weight: 500;
        margin: 0;
    }
}

